#include <stdio.h>
#include <limits.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, H;
        scanf("%d %d", &N, &H);
        int li[N], hi[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &li[i], &hi[i]);
        }
        int dp[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                dp[i][j] = INT_MAX;
            }
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                if (i == 0) {
                    if (j >= li[0] && j <= hi[0]) {
                        dp[i][j] = 0;
                    } else {
                        dp[i][j] = 1;
                    }
                } else {
                    for (int k = 0; k < N; k++) {
                        if (j >= li[i] && j <= hi[i]) {
                            dp[i][j] = dp[i - 1][k] + (k != j);
                        } else {
                            dp[i][j] = dp[i - 1][k] + 1;
                        }
                    }
                }
            }
        }
        int minEnergy = INT_MAX;
        for (int i = 0; i < N; i++) {
            if (dp[N - 1][i] < minEnergy) {
                minEnergy = dp[N - 1][i];
            }
        }
        printf("%d\n", minEnergy);
    }
    return 0;
}

